% Age: 50:70
Age = 50:70;
Coefficient_a_Female_1_31_Luxembourg = [];
Coefficient_b_Female_1_31_Luxembourg = [];
% Age 50
Coefficient_a_Female_1_31_Luxembourg = [Coefficient_a_Female_1_31_Luxembourg 0];
Coefficient_b_Female_1_31_Luxembourg = [Coefficient_b_Female_1_31_Luxembourg 0];
